import type { Theory, ModuleId } from '../types';

const make = (
  id: string, module: ModuleId, name: string, category: string, unitIds: string[],
  definition: string, plain: string, purpose: string, components: string[],
  advantages: string[], limitations: string[], examTriggers: string[],
  relatedTheoryIds: string[], refs: string[],
): Theory => ({
  id, module, name, category, unitIds, definition, definitionRefs: refs, plain, purpose, components,
  advantages, limitations,
  comparisons: relatedTheoryIds.map((against) => ({ against, note: 'Use as a related framework when the case needs a wider explanation.' })),
  example: 'Use this framework to diagnose the situation, link evidence to theory, and recommend practical management action.',
  saExample: 'Apply to a South African workplace by considering resource constraints, regulation, digital inequality, diversity and stakeholder expectations.',
  examTriggers,
  commonMistakes: ['Describing the concept without applying case evidence.', 'Using the framework as a list rather than a diagnostic tool.', 'Forgetting limitations or implementation risks.'],
  relatedTheoryIds, caseIds: [], refs
});

