export const THEORIES: Theory[] = RAW_THEORIES.map((t) =>
  THEORY_OVERRIDES[t.id] ? { ...t, ...THEORY_OVERRIDES[t.id] } : t
);

export function getTheory(id: string) {
  return THEORIES.find((t) => t.id === id);
}
